mapper.select:
SELECT p.* FROM sys_permission p
JOIN sys_role_permission rp ON p.code = rp.permission_code
WHERE rp.role = #{role}

SELECT p.* FROM sys_permission p
WHERE p.code IN (
    SELECT permission_code FROM sys_role_permission rp
    JOIN sys_user u ON rp.role = u.role
    WHERE u.id = #{userId}
    UNION
    SELECT permission_code FROM sys_user_permission up
    WHERE up.user_id = #{userId}
)
